// Test_ID may be blank/null in the uploaded sheet, so do not rely on it.
return $input.all()
  .map((item, index) => {
    const row = item.json;
    const testId = String(row.Test_ID ?? row.TEST_ID ?? row.Post_ID ?? row.ID ?? '').trim();
    const userInput = String(row.User_Input ?? row.USER_INPUT ?? row.Topic ?? row.topic ?? '').trim();
    return {
      json: {
        ...row,
        __row_index: index,
        __merge_key: testId || userInput || String(index),
      },
    };
  })
  .filter(item => {
    const existing = item.json.Model_Output;
    return existing === undefined || existing === null || String(existing).trim() === '';
  });

