// Build the output file after the row loop has completed.
// Test_ID can be null, so merge by stable row key first, then Test_ID, then User_Input.
const incomingItems = $input.all();

function flattenProcessedItems(items) {
  const rows = [];
  for (const item of items) {
    if (Array.isArray(item.json?.data)) {
      for (const nested of item.json.data) rows.push({ json: nested });
    } else {
      rows.push(item);
    }
  }
  return rows;
}

function normalize(value) {
  return String(value ?? '').trim();
}

function getTestId(row) {
  return normalize(row?.Test_ID ?? row?.TEST_ID ?? row?.Post_ID ?? row?.ID);
}

function getUserInput(row) {
  return normalize(row?.User_Input ?? row?.USER_INPUT ?? row?.Topic ?? row?.topic);
}

function getRowIndex(row) {
  const raw = row?.__row_index;
  return raw === undefined || raw === null || raw === '' ? '' : String(raw);
}

function getMergeKey(row, index) {
  return normalize(row?.__merge_key) || getTestId(row) || getUserInput(row) || String(index);
}

function getModelOutput(row) {
  const value =
    row?.Model_Output ??
    row?.model_output ??
    row?.post_content ??
    row?.output?.post_content ??
    row?.output?.output?.post_content ??
    '';
  return typeof value === 'string' ? value.trim() : String(value ?? '').trim();
}

const byMergeKey = new Map();
const byTestId = new Map();
const byUserInput = new Map();
const byRowIndex = new Map();

for (const item of flattenProcessedItems(incomingItems)) {
  const row = item.json;
  const output = getModelOutput(row);
  if (!output) continue;

  const mergeKey = getMergeKey(row);
  const testId = getTestId(row);
  const userInput = getUserInput(row);
  const rowIndex = getRowIndex(row);

  if (mergeKey) byMergeKey.set(mergeKey, output);
  if (testId) byTestId.set(testId, output);
  if (userInput) byUserInput.set(userInput, output);
  if (rowIndex) byRowIndex.set(rowIndex, output);
}

const originalRows = $('Extract First Sheet Data').all();

return originalRows.map((row, index) => {
  const original = row.json;
  const mergeKey = getMergeKey(original, index);
  const testId = getTestId(original);
  const userInput = getUserInput(original);
  const rowIndex = String(index);

  const generatedOutput =
    byMergeKey.get(mergeKey) ??
    byTestId.get(testId) ??
    byUserInput.get(userInput) ??
    byRowIndex.get(rowIndex);

  const { __row_index, __merge_key, ...cleanOriginal } = original;
  return {
    json: {
      ...cleanOriginal,
      Model_Output: generatedOutput ?? original.Model_Output ?? '',
    },
  };
});
